import React, { useState } from "react";
import axios from "axios";

function StockDetails() {
  const [mode, setMode] = useState(null); // "us" or "india"
  const [symbol, setSymbol] = useState("");
  const [data, setData] = useState(null);
  const [error, setError] = useState("");

  const handleFetch = async () => {
    try {
      setError("");
      setData(null);

      let url = "";

      if (mode === "us") {
        url = `/api/stock/${symbol}`;
      } else if (mode === "india") {
        url = `/api/stocks/${symbol}`;
      }

      const res = await axios.get(url);
      setData(res.data);
    } catch (err) {
      console.error(err);
      setError(err.response?.data?.error || "Something went wrong.");
    }
  };

  return (
    <div style={{ padding: "20px" }}>
      <h2>Stock Details</h2>

      {/* Mode selection buttons */}
      <div style={{ marginBottom: "20px" }}>
        <button onClick={() => { setMode("us"); setData(null); setError(""); }}>
          US Stocks
        </button>{" "}
        <button onClick={() => { setMode("india"); setData(null); setError(""); }}>
          Indian Stocks
        </button>
      </div>

      {/* Input field only if mode selected */}
      {mode && (
        <div style={{ marginBottom: "20px" }}>
          <input
            type="text"
            placeholder="Enter Stock Symbol"
            value={symbol}
            onChange={(e) => setSymbol(e.target.value)}
            style={{ width: "200px", padding: "5px" }}
          />{" "}
          <button onClick={handleFetch}>Fetch Details</button>
        </div>
      )}

      {/* Error message */}
      {error && <p style={{ color: "red" }}>{error}</p>}

      {/* Display data */}
      {data && (
        <div style={{ marginTop: "20px" }}>
          <pre
            style={{
              background: "#f5f5f5",
              padding: "10px",
              borderRadius: "5px",
            }}
          >
            {JSON.stringify(data, null, 2)}
          </pre>
        </div>
      )}
    </div>
  );
}

export default StockDetails;
